module decoder_3to8(
    input [2:0] a,    // 3-bit input
    output reg [7:0] obf_y // 8-bit output
);

// Decoder logic
always @(*) begin
    obf_y = 8'b00000000;  // Default output
    case (a)
        3'b000: obf_y = 8'b00000001;
        3'b001: obf_y = 8'b00000010;
        3'b010: obf_y = 8'b00000100;
        3'b011: obf_y = 8'b00001000;
        3'b100: obf_y = 8'b00010000;
        3'b101: obf_y = 8'b00100000;
        3'b110: obf_y = 8'b01000000;
        3'b111: obf_y = 8'b10000000;
    endcase
end

endmodule
